module SimpleHellaCacheIFReplayQueue (
	clock,
	reset,
	io_nack_valid,
	io_nack_bits,
	io_resp_valid,
	io_resp_bits_tag,
	io_replay_ready,
	io_replay_valid
);
	input clock;
	input reset;
	input io_nack_valid;
	input [5:0] io_nack_bits;
	input io_resp_valid;
	input [7:0] io_resp_bits_tag;
	input io_replay_ready;
	output wire io_replay_valid;
	wire _nackq_io_enq_ready;
	wire _nackq_io_deq_valid;
	reg replaying;
	wire io_replay_valid_0 = _nackq_io_deq_valid & ~replaying;
	wire replay_complete = (io_resp_valid & replaying) & (io_resp_bits_tag == 8'h00);
	wire nack_head = (io_nack_valid & _nackq_io_deq_valid) & (io_nack_bits == 6'h00);
	wire nackq_io_enq_valid = io_nack_valid & ~nack_head;
	always @(posedge clock)
		if (reset)
			replaying <= 1'h0;
		else
			replaying <= ~(nack_head | replay_complete) & ((io_replay_ready & io_replay_valid_0) | replaying);
	Queue3_UInt2 nackq(
		.clock(clock),
		.reset(reset),
		.io_enq_ready(_nackq_io_enq_ready),
		.io_enq_valid(nackq_io_enq_valid),
		.io_deq_ready(replay_complete),
		.io_deq_valid(_nackq_io_deq_valid)
	);
	assign io_replay_valid = io_replay_valid_0;
endmodule
